#include <stdio.h>
#include <math.h>

long long comb(int n, int k) {
    if (k > n - k) k = n - k;
    long long result = 1;
    for (int i = 0; i < k; ++i) {
        result = result * (n - i) / (i + 1);
    }
    return result;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int S, N, M, K;
        scanf("%d %d %d %d", &S, &N, &M, &K);
        double prob = 0.0;
        for (int i = K; i <= M; ++i) {
            long long waysToChooseFriends = comb(M - 1, i - 1);
            long long waysToChooseOthers = comb(S - M, N - i);
            long long totalWays = comb(S - 1, N - 1);
            prob += (double)(waysToChooseFriends * waysToChooseOthers) / totalWays;
        }
        printf("%.6f\n", prob);
    }
    return 0;
}

