import math

def comb(n, k):
    if k > n - k: k = n - k
    result = 1
    for i in range(k):
        result = result * (n - i) / (i + 1)
    return result

def main():
    T = int(input())
    for _ in range(T):
        S, N, M, K = map(int, input().split())
        prob = 0.0
        for i in range(K, M + 1):
            ways_to_choose_friends = comb(M - 1, i - 1)
            ways_to_choose_others = comb(S - M, N - i)
            total_ways = comb(S - 1, N - 1)
            prob += (ways_to_choose_friends * ways_to_choose_others) / total_ways
        print(f"{prob:.6f}")

if __name__ == '__main__':
    main()

